// 八上·第五章 建设美丽中国
// ─────────────────────────────────────────────

// C5_S1 自然灾害（原4题，追加10题）
window.QB_G8_C5_S1.push(
  {c:'中国',q:'中国地震多发区主要分布在哪里？原因是什么？',o:['东部沿海，海浪侵蚀','西南（四川、云南、西藏）、西北（新疆）、台湾；位于欧亚板块与太平洋板块、印度洋板块交界处','东北平原，地基软','华北平原，地形平坦'],a:1,e:'中国地震带：①台湾（太平洋板块与欧亚板块碰撞）②西南（印度洋板块撞击欧亚板块形成青藏高原，地壳活动剧烈）③西北（内陆断层带）。2008年四川汶川8.0级地震造成巨大损失。'},
  {c:'中国',q:'洪涝灾害在中国哪些地区最常见？为什么？',o:['西北干旱地区','东部季风区（尤其是长江、黄河、淮河等大河中下游）；受夏季风影响，降水集中，河流水量暴涨','青藏高原','东北山区'],a:1,e:'东部季风区洪涝频发原因：①夏季降水集中（6-8月）占年降水70-80%②大河中下游地势低平排水慢③人类活动（围湖造田减少蓄洪能力）。1998年长江大洪水是近年最典型案例。'},
  {c:'中国',q:'北方地区（华北、东北）最主要的气象灾害是？',o:['台风','旱灾（春旱最严重）和寒潮','洪涝','高温热浪'],a:1,e:'华北春旱：春季气温回升+降水少+蒸发大，旱情严重，影响冬小麦生长。东北则常受寒潮影响（早霜冻害）。台风主要影响东南沿海，北方较少受台风直接侵袭。'},
  {c:'中国',q:'沙尘暴主要影响中国哪些地区？沙尘来源是哪里？',o:['东南沿海','华北（北京等）、东北南部；沙尘来源主要是西北内蒙古、甘肃等地的沙漠和荒漠草原','南方各省','青藏高原'],a:1,e:'沙尘暴：西北风将新疆、内蒙古、甘肃等地的沙尘吹向华北，春季最严重（植被稀疏+风力大）。北京沙尘暴每年发生约4-10次。治理：西北防护林体系（三北防护林）建设。'},
  {c:'中国',q:'台风预警等级分为哪几级？登陆前应该做什么准备？',o:['只有一个等级','蓝-黄-橙-红四级（红色最高）；准备：远离海边、加固门窗、储备食物水和手电、收听官方预警','只需关注天气预报即可','预警期间照常户外活动'],a:1,e:'台风预警（蓝→黄→橙→红，由低到高）：红色预警意味着风力12级以上。防台措施：①不去海边②加固房屋③准备应急物资④收听官方播报⑤必要时按指示撤离低洼地。'},
  {c:'中国',q:'地震来临时（有感地震），正确的应对措施是？',o:['立即跑出楼外','室内：蹲在坚固家具旁或靠内墙角（三角地带），保护头部；不要跳楼；震后有序撤离','立即乘电梯下楼','打电话向家人报平安'],a:1,e:'地震"黄金12秒"：①不要跑，就地蹲在桌子旁或内墙角②用双手护头③远离窗户和外墙④不要使用电梯⑤主震停止后有序撤离至空旷地。"跑"和"跳楼"是错误行为！'},
  {c:'中国',q:'"防灾减灾日"是中国的哪一天？设立的原因是什么？',o:['7月28日（唐山大地震纪念）','5月12日（汶川地震周年纪念日），旨在提高防灾减灾意识和应急能力','1月1日','3月12日（植树节）'],a:1,e:'中国防灾减灾日定于每年5月12日（2008年汶川大地震纪念日）。每年这一天开展避震演练、防灾知识普及等活动，目的是提高全民防灾减灾意识和自救互救能力。'},
  {c:'中国',q:'旱灾对中国农业生产的主要影响是？',o:['使粮食增产','导致农作物歉收减产，水资源短缺，牧场退化，严重时引发饥荒','使气候湿润','增加降水'],a:1,e:'旱灾影响：①农作物因缺水而减产（华北春旱影响小麦，西南伏旱影响水稻）②人畜饮水困难③牧场退化（西北、内蒙古）④严重旱灾可引发地区性粮食危机。'},
  {c:'中国',q:'三北防护林工程（"绿色长城"）建设的主要目的是？',o:['为木材生产','防风固沙、保护农田、减少沙尘暴，改善西北华北生态环境','增加旅游景点','发展林业经济'],a:1,e:'三北防护林（1978年启动，建设周期73年）：在东北、华北、西北建设大型防护林带，防风固沙，阻止荒漠化向东扩展，是中国最大的生态工程，被称为"绿色万里长城"。'},
  {c:'中国',q:'洪涝灾害的防治措施有哪些？',o:['只能等洪水自然退去','修建水库（调洪蓄洪）、加固堤坝（工程措施）；退耕还林还草、植树造林（生物措施）；建立预警系统；合理规划泄洪区','只靠植树造林','禁止所有人住在河边'],a:1,e:'防洪综合措施：①工程：修水库（三峡防洪）、加固堤坝、疏浚河道、修建分洪蓄洪区②生物：植树造林、退耕还林（减少水土流失）③管理：洪水预警系统、防洪预案④政策：禁止围湖造田。'}
);

// C5_S2 环境与发展（原3题，追加10题）
window.QB_G8_C5_S2.push(
  {c:'中国',q:'中国雾霾（PM2.5）污染最严重的地区是？主要原因是？',o:['海南岛','华北平原（京津冀）；工业排放+燃煤取暖+汽车尾气+地形不利（山区围绕）','青藏高原','海南岛'],a:1,e:'京津冀雾霾成因：①工业（钢铁、化工）排放大量烟尘②冬季燃煤取暖③大量汽车尾气④太行山等山脉围绕，风力弱，污染物难以扩散。治理：淘汰落后产能、清洁取暖、限行限号。'},
  {c:'中国',q:'"生态文明建设"（习近平生态文明思想）的核心理念是？',o:['"先污染后治理"','绿水青山就是金山银山；人与自然和谐共生；节约资源保护环境是基本国策','经济发展第一，环境保护第二','只要GDP增长，环境可以牺牲'],a:1,e:'"两山论"（习近平，2005年）：绿水青山就是金山银山，保护生态环境就是保护生产力。生态文明建设已被写入宪法，是"五位一体"总体布局（经济、政治、文化、社会、生态）之一。'},
  {c:'中国',q:'可持续发展的含义是？',o:['只看当代人的发展需求','既满足当代人的需求，又不损害后代人满足其需求的能力，实现经济、社会、环境的协调发展','只保护环境不发展经济','只考虑自然资源的使用'],a:1,e:'可持续发展（Sustainable Development）=在满足当代需求的同时，不危及后代满足其需求的发展模式。核心：代际公平+社会公平+经济发展+生态保护。1987年《我们共同的未来》提出。'},
  {c:'中国',q:'中国酸雨危害最严重的地区是？主要成因是什么？',o:['东北工业区','长江以南（四川盆地、贵州、广东等）；主要是燃烧含硫煤产生SO₂、氮氧化物与水反应形成酸雨','西北干旱区','北京周边'],a:1,e:'酸雨危害区主要在中国南方（四川、贵州、两湖、广东），形成原因：①南方多燃烧高硫煤②降雨多，利于酸性物质积累③南方岩石缓冲能力弱。危害：腐蚀建筑、破坏植被、污染土壤水体。'},
  {c:'中国',q:'中国为什么要建立"自然保护区"？已有多少个？',o:['为了发展旅游业','保护珍稀濒危野生动植物和重要生态系统；中国已建约2700多个自然保护区','为了科学研究','为了农业生产'],a:1,e:'中国自然保护区：保护濒危物种（大熊猫、东北虎、白鳍豚、丹顶鹤等）和重要生态系统。著名保护区：四川卧龙（大熊猫）、东北虎豹国家公园（东北虎）、三江源（江河源头生态）。'},
  {c:'中国',q:'"碳中和"需要哪些主要途径来实现？',o:['只需种树','减少碳排放（节能、清洁能源替代、提高能效）+增加碳吸收（植树造林、碳捕集）+碳交易市场','只需关闭所有工厂','只靠政府政策'],a:1,e:'碳中和路径：①能源结构转型（光伏、风电、核电替代煤炭）②提高能效（建筑、工业、交通节能）③植树造林（增加碳汇）④碳捕集封存技术（CCUS）⑤碳交易市场（碳权交易让减排有经济价值）。'},
  {c:'中国',q:'中国在新能源领域取得了哪些重要成就？',o:['尚未开始发展新能源','光伏、风电装机容量全球第一，新能源汽车产销量全球第一，已成为全球最大新能源国家','只有风能发达','太阳能和风能刚刚起步'],a:1,e:'中国新能源成就：①光伏（太阳能）：装机容量和产量全球第一②风电：陆上+海上装机容量全球第一③新能源汽车：产销量连续多年全球第一④水电：三峡等世界级水电站，装机全球第一。'},
  {c:'中国',q:'"循环经济"的含义是？举一个例子。',o:['生产-消费-废弃的单向流程','废弃物再利用，实现资源循环使用，减少废物排放。例：工业废水处理后循环使用，废钢铁回收重新炼钢','只回收纸张','减少所有生产活动'],a:1,e:'循环经济（Circular Economy）：模拟自然界物质循环，让废弃物变成新的原料再利用。例子：废纸回收造纸、废金属冶炼、餐厨垃圾制沼气、工业废热用于供暖、尾矿再利用。减少资源消耗和环境污染。'},
  {c:'中国',q:'中国城市垃圾分类的主要类别有哪些？',o:['只分为垃圾和废品两类','可回收物、有害垃圾、厨余垃圾（湿垃圾）、其他垃圾（干垃圾）','只分为大垃圾和小垃圾','无需分类统一处理'],a:1,e:'城市垃圾四分类（上海等地已强制实施）：①可回收物（废纸、金属、玻璃、塑料）②有害垃圾（电池、药品、灯管）③厨余垃圾（食物残渣）④其他垃圾（普通生活垃圾）。正确分类减少填埋和焚烧。'},
  {c:'中国',q:'"绿色出行"包括哪些方式？对环境有什么意义？',o:['只有步行算绿色出行','乘坐公共交通（公交、地铁）、骑自行车/共享单车、步行、拼车；减少私家车使用，降低碳排放和城市拥堵','开私家车也是绿色出行','飞机是绿色出行'],a:1,e:'绿色出行：①降低碳排放（减少化石燃料消耗）②缓解城市交通拥堵③减少PM2.5排放。计算：一辆私家车CO₂排放量≈20个人骑自行车。城市鼓励公共交通+非机动车+步行的"绿色出行体系"。'}
);

// ─────────────────────────────────────────────
// 八下·第六章 中国的地理差异
// ─────────────────────────────────────────────

// C6 四大地理区域（原4题，追加10题）
window.QB_G8_C6.push(
  {c:'中国',q:'南方地区和北方地区在农业上最显著的差异是？',o:['北方产量更高','南方以水田水稻为主，北方以旱地小麦玉米为主；这与降水和气温的差异直接相关','两者完全相同','南方以小麦为主'],a:1,e:'秦岭-淮河以南：降水多（>800mm），气温高，以水田为主，主要种水稻、油菜等；以北：降水少（400-800mm），气温低，以旱地为主，主要种小麦、玉米、大豆。'},
  {c:'中国',q:'西北地区主要的自然景观从东到西变化的规律是？',o:['从森林到草原再到荒漠（随降水减少）','从荒漠到草原再到森林','从高原到平原','从山地到盆地'],a:0,e:'西北地区：从东（大兴安岭西侧）到西（新疆），随距海洋越来越远，降水越来越少，自然景观依次变化：草原→荒漠草原→荒漠（沙漠/戈壁），体现干旱程度的递增。'},
  {c:'中国',q:'青藏地区农业生产的限制性因素是？农业分布在哪里？',o:['降水不足是唯一限制因素','气温低（热量不足）是最主要限制因素；农业（种植业）主要分布在海拔较低的河谷地带（雅鲁藏布江谷地等）','土壤贫瘠','缺乏劳动力'],a:1,e:'青藏高原高寒，热量是最大限制因素。少数河谷（雅鲁藏布江谷地、湟水谷地）海拔较低（2000-3000m），气温稍高，可种植青稞（耐寒作物）、小麦、油菜。"高原江南"——林芝。'},
  {c:'中国',q:'四大地理区域划分的主要依据是？',o:['只看经济发展水平','综合地形、气候、植被、农业生产等自然和人文地理特征的差异来划分','只看行政区划','只看民族分布'],a:1,e:'中国四大地理区域的划分：综合考虑地形（高原、平原、盆地）、气候（温度、降水）、植被（草原、森林、荒漠）、土壤、农业生产方式等多种地理要素的综合差异。'},
  {c:'中国',q:'北方和西北地区的分界线是？',o:['秦岭-淮河','400mm等降水量线（大兴安岭-长城沿线）','青藏高原边缘','黄河'],a:1,e:'北方与西北的分界：400mm年降水量线（大兴安岭-阴山-贺兰山-乌鞘岭一线），大致与长城走向一致。400mm以东为半湿润区（北方），以西为半干旱/干旱区（西北）。'},
  {c:'中国',q:'青藏地区与其他三个地区的分界线是？',o:['长江','黄河','青藏高原边缘（昆仑山-祁连山-横断山）','大兴安岭'],a:2,e:'青藏地区的自然边界：西起昆仑山、祁连山（与西北地区分界），东侧横断山（与南方地区分界），东北端巴颜喀拉山等（与北方地区分界）。'},
  {c:'中国',q:'南方地区的主要气候类型是？最突出的气候特点是？',o:['温带大陆性气候，干旱','亚热带和热带季风气候，雨热同期，夏季高温多雨','高原山地气候','温带季风气候'],a:1,e:'南方：秦岭-淮河以南，主要是亚热带季风气候（长江流域）和热带季风气候（海南、云南最南部）。气候特点：夏季高温多雨，冬季温和少雨，年降水量>800mm，无明显冬季（或冬季短暂温和）。'},
  {c:'中国',q:'北方地区的代表性植被类型是？',o:['热带雨林','亚热带常绿阔叶林','温带落叶阔叶林（东部）和草原（西部）','荒漠'],a:1,e:'北方地区植被：东部（湿润区）以温带落叶阔叶林为主；向西（半湿润半干旱区）过渡为温带草原。典型植物：桦树、杨树、落叶松（东北）、白杨、柳树（华北）。'},
  {c:'中国',q:'西北地区为什么说是"内陆性气候"？',o:['因为有内陆海','远离海洋，海洋水汽难以到达，降水稀少，气温日较差和年较差大','因为有沙漠','因为人口少'],a:1,e:'西北内陆性气候特征：①远离海洋，降水极少（新疆<200mm，吐鲁番<10mm）②气温年较差大（夏热冬冷）③气温日较差大（昼夜温差大，有利于瓜果（哈密瓜）糖分积累）④多风沙。'},
  {c:'中国',q:'地理分界线"秦岭-淮河"在中国南北对比中有哪些具体分界含义？（至少写出4个）',o:['只是省界线','800mm等降水量线、1月0℃等温线、亚热带与暖温带分界、湿润与半湿润分界、水田与旱地分界、南北方分界','只是气候分界线','只是河流分界线'],a:1,e:'秦岭-淮河多重含义：①800mm等降水量线②1月0℃等温线③亚热带与暖温带（温带季风气候南界）④湿润与半湿润分界⑤水田与旱地分界⑥常绿阔叶林与落叶阔叶林分界⑦中国南方与北方分界。'}
);

