// 八下·第九章 西北地区
// ─────────────────────────────────────────────

// C9_S1 西北概况（原3题，追加10题）
window.QB_G8_C9_S1.push(
  {c:'西北',q:'西北地区的主要地形特征是？',o:['以平原为主，地势低平','盆地和山地相间（"三山夹两盆"——天山、阿尔泰山、昆仑山/祁连山夹准噶尔盆地和塔里木盆地）','以高原为主','以丘陵为主'],a:1,e:'新疆地形："三山夹两盆"：阿尔泰山（北）夹准噶尔盆地（北疆），天山（中）夹塔里木盆地（南疆），昆仑山-祁连山（南）。这一地形格局决定了南北疆气候、农业的显著差异。'},
  {c:'西北',q:'新疆盛产哈密瓜和葡萄的原因是？',o:['降水充足，水分供应好','气候干旱，昼夜温差大（糖分不被夜间呼吸消耗，积累多），光照充足（有效光合时间长），灌溉农业（坎儿井+雪水）','土壤最肥沃','气温最高'],a:1,e:'吐鲁番瓜果：①温差大（昼夜温差>20℃），夜间低温使有机物（糖分）消耗少，积累多②光照充足（年日照3000小时+）③雪水灌溉（坎儿井）。"吐鲁番的葡萄"含糖量高达18-22%，品质优异。'},
  {c:'西北',q:'西北地区的主要少数民族是？',o:['彝族、壮族','维吾尔族（新疆）、哈萨克族（新疆）、回族（宁夏、甘肃）、蒙古族（内蒙古）','傣族、苗族','藏族、纳西族'],a:1,e:'西北少数民族：①新疆：维吾尔族（最多）、哈萨克族、柯尔克孜族②宁夏、甘肃：回族③内蒙古：蒙古族④甘肃：东乡族、裕固族。各民族有独特的宗教文化（多信仰伊斯兰教）。'},
  {c:'西北',q:'"坎儿井"是新疆特有的引水工程，它的原理是什么？',o:['用水泵抽取地下水','在戈壁滩地下挖掘暗渠，利用地形坡度引导天山雪水在地下流动，最终到达农田；地下渠防止了蒸发，适应干旱气候','用高坝拦蓄河水','用太阳能泵引水'],a:1,e:'坎儿井（新疆古老引水工程）：①在山麓地带开竖井（找地下水）→横向暗渠连接竖井引水→暗渠流向农田的明渠。②全程地下流动防止蒸发（干旱区蒸发极强）③利用地形坡降自流，无需动力。是古代劳动人民的智慧结晶。'},
  {c:'西北',q:'塔克拉玛干沙漠有什么地理特点？',o:['是中国最小的沙漠','是中国最大的沙漠（约33万km²），也是世界第二大流动沙漠，位于塔里木盆地中部，气候极度干旱（年降水<10mm）','降水较多','位于东北地区'],a:1,e:'塔克拉玛干沙漠（维吾尔语意为"进去出不来的地方"）：①面积约33万km²，中国最大②世界第二大流动沙漠（沙丘高达100-200m）③年降水<10mm，极度干旱④吐鲁番最低处（艾丁湖，-154m）在其北缘。'},
  {c:'西北地区',q:'内蒙古草原的主要生态问题是什么？如何治理？',o:['水土流失','草场退化（过度放牧+气候干旱）和沙化；治理：建立休牧制度、围封禁牧、种植牧草、发展人工草场、减少超载放牧','水资源过多','森林砍伐'],a:1,e:'内蒙古草场退化：①过度放牧（载畜量超过草场承载量）②气候变化（降水减少）③矿产开发破坏草场。治理：草场围栏（防止混牧）→休牧（让草场休养生息）→补播牧草→发展人工草场→推广舍饲圈养减少野外放牧。'},
  {c:'西北',q:'西北地区的能源优势是什么？如何开发利用？',o:['风能和太阳能不足','风能（内蒙古、新疆风力强劲）和太阳能（日照充足）资源极为丰富，以及油气资源（新疆）；通过西电东送和西气东输输往东部','只有石油','只有天然气'],a:1,e:'西北能源：①新疆天然气（塔里木）→西气东输②内蒙古+新疆风电（风力强，风场大）→西电东送③新疆+青海+甘肃光伏（日照充足）→西电东送④新疆石油（克拉玛依）。西北能源基地化是重要战略。'},
  {c:'西北',q:'为什么新疆南北疆（以天山为界）的气候差异显著？',o:['南北纬度差异大','天山山脉阻隔：①北疆（准噶尔）受西风气流和北冰洋气流影响，降水相对较多（200-500mm），冬季积雪厚；②南疆（塔里木）三面环山阻挡水汽，极度干旱（<50mm）','地形完全相同，气候无差异','南疆纬度更高，更寒冷'],a:1,e:'天山是南北疆的气候分界线：①北疆：西风从大西洋带来少量水汽，可穿越准噶尔盆地西部缺口进入，相对湿润，降水100-500mm②南疆：塔里木盆地三面被高山（天山、昆仑山、帕米尔）封闭，水汽进不来，年降水<50mm，极端干旱。'},
  {c:'西北',q:'西北地区为什么是古丝绸之路的重要通道？',o:['西北气候最舒适','连接中国东部与中亚、欧洲的陆上通道（河西走廊→塔里木盆地沿山麓绿洲串联），是古代丝绸、瓷器、香料贸易的主干道，也是文化交流的桥梁','西北全是沙漠，古人不能通行','因为西北有海港'],a:1,e:'丝绸之路（汉代张骞出使西域开拓）：长安（西安）→河西走廊（甘肃）→玉门关/阳关→西域（新疆绿洲城市：敦煌、楼兰、于阗、龟兹）→帕米尔高原→中亚→波斯→罗马。是古代最重要的东西方贸易和文化交流通道。'},
  {c:'西北',q:'敦煌在西北历史地理中有什么重要意义？',o:['是新疆的首府','是古代丝绸之路上的重要咽喉和商贸中心（甘肃西端），以莫高窟（千佛洞）壁画和文物著名，是东西方文化交汇的艺术宝库','是现代工业中心','是西北最大的港口'],a:1,e:'敦煌（甘肃）：古代丝绸之路的战略要地（出玉门关进入西域前的最后重要城市）。莫高窟（世界文化遗产）：735个洞窟，45000多m²壁画，记录了从北凉到元代1000年的佛教艺术和中西文化交流历史，是无价之宝。'},
{c:'西北农业',q:'我国西北地区与北方地区的地理分界线是？',o:['400毫米年等降水量线','秦岭-淮河一线','昆仑山-祁连山一线','黑河-腾冲一线'],a:0,e:'我国西北地区与北方地区的地理分界线是400毫米年等降水量线，该线同时也是我国季风区与非季风区分界线的主体段；秦岭-淮河是南北方分界线，昆仑山-祁连山是青藏地区与其他区域分界线，黑河-腾冲是我国人口地理分界线。'},
{c:'西北农业',q:'我国西北地区最主要的地形类型是？',o:['平原和丘陵','山地和平原','高原和盆地','山地和丘陵'],a:2,e:'我国西北地区地形以高原和盆地为主，核心地形区包括内蒙古高原、塔里木盆地、准噶尔盆地，山地多分布在盆地边缘，整体地形开阔。'},
{c:'西北农业',q:'我国西北地区最突出的自然地理特征是？',o:['湿热','冷湿','高寒','干旱'],a:3,e:'我国西北地区深居内陆、距海遥远，加上山脉阻挡，海洋湿润气流难以到达，降水稀少，干旱是本区最核心的自然地理特征；湿热是南方地区特征，冷湿是东北地区特征，高寒是青藏地区特征。'},
{c:'西北农业',q:'我国西北地区的河流大多属于？',o:['内流河','外流河','常年性河流','注入太平洋的河流'],a:0,e:'我国西北地区气候干旱，降水稀少，河流大多发源于山地，最终消失在沙漠或注入内陆湖泊，是我国内流河分布最集中的区域；外流河主要分布在东部季风区。'},
{c:'西北农业',q:'我国最大的内流河，位于新疆塔里木盆地的是？',o:['黄河','长江','塔里木河','额尔齐斯河'],a:2,e:'塔里木河是我国最大的内流河，位于新疆塔里木盆地，水源主要来自天山、昆仑山的高山冰雪融水，是塔里木盆地绿洲农业的核心水源；额尔齐斯河是我国西北地区唯一注入北冰洋的外流河。'},
{c:'西北农业',q:'我国西北地区的植被景观从东向西的变化规律是？',o:['荒漠-荒漠草原-草原','草原-荒漠-荒漠草原','荒漠草原-草原-荒漠','草原-荒漠草原-荒漠'],a:3,e:'我国西北地区年降水量从东向西逐渐减少，受降水影响，植被景观从东向西依次呈现草原-荒漠草原-荒漠的变化规律，体现了降水对自然景观的决定性影响。'},
{c:'西北农业',q:'我国西北地区最主要的农业生产部门是？',o:['畜牧业','种植业','林业','渔业'],a:0,e:'我国西北地区气候干旱，草场广布，是我国重要的畜牧业基地，拥有内蒙古牧区、新疆牧区两大国家级牧区，畜牧业是本区最核心的农业生产部门。'},
{c:'西北农业',q:'受干旱气候影响，我国西北地区的种植业类型主要是？',o:['水田农业','旱作农业','灌溉农业和绿洲农业','河谷农业'],a:2,e:'我国西北地区降水稀少，种植业必须依靠水源灌溉才能发展，因此形成了灌溉农业（内蒙古、宁夏、甘肃片区）和绿洲农业（新疆盆地边缘）两大核心类型；水田农业在南方，旱作农业在北方，河谷农业在青藏地区。'},
{c:'西北农业',q:'被誉为“塞上江南”的宁夏平原和河套平原，其农业灌溉水源主要来自？',o:['黄河','长江','高山冰雪融水','大气降水'],a:0,e:'宁夏平原和河套平原位于黄河上游，依托黄河丰富的水源发展灌溉农业，物产丰富、农业发达，被誉为“塞上江南”，是我国西北地区重要的商品粮基地。'},
{c:'西北农业',q:'新疆塔里木盆地、准噶尔盆地边缘的绿洲农业，其核心灌溉水源是？',o:['大气降水','河流水','湖泊水','高山冰雪融水和山地降水'],a:3,e:'新疆深居内陆，盆地内降水极少，盆地边缘的绿洲农业，水源主要来自周边天山、昆仑山、阿尔泰山等山地的高山冰雪融水，以及少量山地降水，水源直接决定了绿洲的分布范围。'},
{c:'西北农业',q:'新疆地区为适应干旱环境，修建的古老引水工程，能有效减少水分蒸发的是？',o:['都江堰','灵渠','坎儿井','京杭大运河'],a:2,e:'坎儿井是新疆吐鲁番等地区的特色古老引水工程，由竖井、暗渠、明渠等部分组成，暗渠在地下输水，能极大减少干旱环境下的水分蒸发，是当地绿洲农业的重要保障。'},
{c:'西北农业',q:'新疆地区盛产的哈密瓜、葡萄等瓜果甜度极高，其核心自然原因是？',o:['降水丰富，水源充足','土壤肥沃，有机质含量高','种植历史悠久，品种优良','夏季光照充足，昼夜温差大，糖分积累多'],a:3,e:'新疆属于温带大陆性气候，夏季晴天多、光照充足，植物光合作用强；昼夜温差大，夜晚气温低，植物呼吸作用弱，糖分消耗少、积累量大，因此瓜果甜度极高、品质优良。'},
{c:'西北农业',q:'制约我国西北地区农业发展的最主要自然因素是？',o:['水资源不足','热量不足','地形崎岖','土壤贫瘠'],a:0,e:'我国西北地区深居内陆，气候干旱，降水稀少，水资源极度匮乏，水资源不足是制约本区农业发展的最核心自然因素，农业生产的分布完全受水源条件约束。'},
{c:'西北农业',q:'我国西北地区年降水量的整体分布规律是？',o:['从南向北逐渐增加','从西向东逐渐减少','从东向西逐渐减少','从北向南逐渐减少'],a:2,e:'我国西北地区的降水主要来自东部太平洋，距海越远降水越少，因此年降水量整体呈现从东向西逐渐减少的分布规律，直接造成了东西部自然景观的显著差异。'},
{c:'西北农业',q:'我国西北地区唯一的外流河，也是我国唯一注入北冰洋的河流是？',o:['塔里木河','黄河','长江','额尔齐斯河'],a:3,e:'额尔齐斯河发源于我国新疆阿尔泰山南麓，向北流出我国国境，最终注入北冰洋，是我国西北地区唯一的外流河，也是我国唯一注入北冰洋的河流。'},
{c:'西北农业',q:'我国内蒙古牧区的代表性优良畜种，被称为“草原骄子”的是？',o:['三河马、三河牛','牦牛、藏绵羊','细毛羊','滩羊'],a:0,e:'三河马、三河牛是我国内蒙古牧区的代表性优良畜种，适应草原游牧环境，体质健壮，被誉为“草原骄子”；牦牛、藏绵羊是青藏地区畜种，细毛羊是新疆牧区代表，滩羊主产于宁夏。'},
{c:'西北农业',q:'我国新疆牧区的代表性优良畜种，适应山地牧场环境的是？',o:['三河牛','牦牛','新疆细毛羊','滩羊'],a:2,e:'新疆细毛羊是我国新疆牧区的代表性优良畜种，适应新疆的山地牧场环境，产毛量高、毛质优良，是我国优质毛用羊的核心品种。'},
{c:'西北农业',q:'受干旱气候影响，我国西北地区分布最广泛的地表景观是？',o:['森林','草原','沼泽','荒漠和荒漠草原'],a:3,e:'我国西北地区大部分区域年降水量在400毫米以下，西部盆地内年降水量甚至不足50毫米，因此分布最广泛的地表景观是荒漠和荒漠草原，仅东部和山地边缘有连片草原分布。'},
{c:'西北农业',q:'下列关于我国西北地区地理位置的描述，正确的是？',o:['位于大兴安岭以西，长城和昆仑山-阿尔金山以北','位于秦岭-淮河以南，青藏高原以东','位于横断山脉以西，昆仑山以南','位于大兴安岭以东，秦岭-淮河以北'],a:0,e:'我国西北地区位于大兴安岭以西，长城和昆仑山-阿尔金山以北，主要包括新疆、内蒙古、宁夏和甘肃北部，是我国跨经度最广的地理区域。'},
{c:'西北农业',q:'下列农作物中，最适宜在我国西北地区干旱环境下种植的是？',o:['水稻','甘蔗','长绒棉','油菜'],a:2,e:'新疆地区夏季气温高、晴天多、光照充足，昼夜温差大，非常适宜长绒棉生长，是我国最大的长绒棉生产基地，产量和品质均居全国首位；水稻、甘蔗、油菜均为南方高需水农作物，不适宜西北干旱环境种植。'}
);

// 塔里木盆地
window.QB_G8_C9_S2.push(
  {c:'西北',q:'西部大开发战略的主要内容有哪些？',o:['只是基础设施建设','基础设施建设（铁路公路管道）、生态保护（退耕还林还草）、资源开发（西气东输西电东送）、引进人才技术、政策优惠','只是吸引外资','只是发展旅游业'],a:1,e:'西部大开发（2000年启动）：①基础设施：青藏铁路、西康铁路、西部公路网②资源开发：西气东输、西电东送③生态：退耕还林、天然林保护④产业：承接东部产业转移⑤人才：优惠政策吸引人才西进。'},
  {c:'塔里木盆地',q:'"退牧还草"政策的主要目的是？',o:['减少牧业收入','减轻草场压力，让退化草场自然恢复植被（改善生态环境），解决西北内蒙古草场荒漠化问题','发展旅游','将牧民全部移民城市'],a:1,e:'退牧还草：在严重退化草场实行禁牧（全年不放牧）或休牧（季节性禁牧），让草场休养生息。国家对牧民提供补偿（饲料粮）。目标：恢复草场植被，防止荒漠化进一步蔓延，是西北生态修复的核心工程之一。'},
  {c:'塔里木盆地',q:'新疆发展棉花种植的优势条件有哪些？',o:['降水丰富，无需灌溉','充足日照（年日照2500-3000小时）+昼夜温差大（有利于纤维发育）+降水少（减少病虫害）+机械化程度高（地势平坦）+大量灌溉水源（天山融雪和地下水）','土壤是全国最肥沃的黑土','纬度最低，气温最高'],a:1,e:'新疆棉花优势：①日照充足（纤维光合好）②温差大（纤维粗且长，品质好）③少降水（减少棉铃虫等病虫害）④冲积平原土地平坦（有利于机械采棉）⑤天山融雪水+坎儿井（灌溉水源）。新疆棉花产量占全国85%以上。'},
  {c:'塔里木盆地',q:'乌鲁木齐是什么城市？有什么地理特征？',o:['新疆自治区首府，有趣地理特征：是世界上距离海洋最远的城市（内陆腹地，距最近海岸约2500km）','甘肃省省会','内蒙古首府','中亚的城市'],a:1,e:'乌鲁木齐（维吾尔语"美丽的牧场"）：新疆维吾尔自治区首府（约400万人），经济和政治中心。地理趣味：是世界上距海洋最远的大城市（距最近海岸约2500km）。天山北麓，准噶尔盆地边缘，气候相对北疆较湿润。'},
  {c:'塔里木盆地',q:'西北地区土地荒漠化的扩展对中国东部地区有什么影响？',o:['完全无影响','沙尘暴：西北沙漠沙尘被西北风吹向华北（北京等）甚至朝鲜半岛、日本；还影响东部农业（沙化耕地减少粮食产量）','只影响西北本地','增加东部降水'],a:1,e:'西北荒漠化→沙尘暴：每年春季（3-5月）西北强风将沙漠沙尘吹向：内蒙古→华北（北京，PM10暴增）→甚至飘扬过海影响韩国日本。防治：三北防护林（绿色长城）是最重要的防风固沙生态屏障。'},
  {c:'西北',q:'新疆的旅游资源有哪些？',o:['以城市旅游为主','喀纳斯（北疆，秋色绝美）、天山天池、吐鲁番火焰山、塔克拉玛干沙漠、喀什古城（古丝路重镇）、大漠胡杨林等，自然和人文景观极为丰富','只有沙漠景观','只有少数民族文化'],a:1,e:'新疆旅游：①自然：喀纳斯（变色湖，秋天五彩）、天山天池（火山湖，冰雪）、塔克拉玛干（沙海）、胡杨林（轮台，"三千年不死"）②人文：喀什老城（古丝路聚会点）、交河故城（楼兰文化）③民俗：维吾尔族歌舞、手工艺。'},
  {c:'塔里木盆地',q:'甘肃张掖的"七彩丹霞"是什么地貌？形成原因是什么？',o:['喀斯特地貌','彩色砂岩地貌（丹霞地貌的一种）；由不同地质时期的红、橙、黄、绿、蓝等不同成分沙砾岩层交错，经地壳抬升和长期风化剥蚀后裸露出来','火山地貌','冰川地貌'],a:1,e:'张掖丹霞：由多种颜色的砂岩和泥岩（含不同铁锰矿物）层状堆积，后经地壳隆起、风雨侵蚀、差异剥蚀，形成色彩斑斓的彩色山地，从空中俯视如同一幅画，是中国最美丹霞之一（UNESCO世界地质公园）。'},
  {c:'塔里木盆地',q:'西北地区发展旅游业面临哪些制约因素？',o:['景观不够吸引人','交通不便（距东部旅客市场遥远，铁路航班有限）、水资源短缺（旅游接待需要水）、环境脆弱（大量游客可能破坏生态）','气候太好旅游者不来','资金不缺'],a:1,e:'西北旅游制约：①距主要客源市场（东部城市）太远，交通成本高②部分地区交通基础设施薄弱③水资源极缺，大量游客难以接待④脆弱生态（沙漠湿地）经不起过度旅游开发。发展"生态旅游"是方向。'},
  {c:'塔里木盆地',q:'黄河上游流经西北（宁夏、甘肃、内蒙古），对该地区有什么重要意义？',o:['无任何意义','提供重要灌溉水源（宁夏平原、河套平原）；黄河两岸形成了"塞外江南"，是西北农业最发达的地区','造成严重洪涝灾害','是西北地区的主要运输通道'],a:1,e:'黄河上游对西北的意义：①宁夏平原（宁夏银川）：黄河灌溉，沙漠中的绿洲农业，"塞上江南"，盛产水稻枸杞②河套平原（内蒙古）：黄河灌溉，是西北重要粮食产区③水力发电（刘家峡、龙羊峡等梯级水电站）。'},
  {c:'塔里木盆地',q:'西北地区风能资源丰富，为什么？主要分布在哪里？',o:['西北降水多，带来大量风','西北（内蒙古、新疆、甘肃）植被稀少，地形平坦，摩擦力小，气压梯度大，风力强劲，是中国陆地风能最丰富的地区','只有新疆有风能','只有近海有风能'],a:1,e:'西北风能：①草原戈壁植被稀，摩擦力小②冬季西伯利亚冷气流+蒙古高压驱动②地形平坦（风速均匀）③年平均风速6-8m/s以上。内蒙古（锡林郭勒、乌兰察布）、新疆（达坂城）是中国最重要的风电基地。'},
{c:'塔里木盆地',q:'我国面积最大的内陆盆地，位于新疆南部的是？',o:['塔里木盆地','准噶尔盆地','四川盆地','柴达木盆地'],a:0,e:'塔里木盆地是我国面积最大的内陆盆地，地处新疆南部，位于天山山脉与昆仑山脉之间，是我国西北干旱区的核心地形单元。'},
{c:'塔里木盆地',q:'塔里木盆地地处新疆南部，位于下列哪两座山脉之间？',o:['大兴安岭与阴山山脉','长白山与武夷山脉','天山山脉与昆仑山脉','祁连山脉与横断山脉'],a:2,e:'塔里木盆地的地形格局为南北两大山脉夹持，北邻天山山脉，南邻昆仑山脉，是新疆“三山夹两盆”地形格局的核心组成部分。'},
{c:'塔里木盆地',q:'塔里木盆地深居亚欧大陆内部，其主要的气候类型是？',o:['温带大陆性气候','温带季风气候','亚热带季风气候','高原山地气候'],a:0,e:'塔里木盆地深居内陆、距海遥远，加上周边山脉阻挡海洋水汽，形成了典型的温带大陆性气候，核心特征是气候极端干旱、降水稀少，气温年较差和日较差极大。'},
{c:'塔里木盆地',q:'塔里木盆地内部分布着我国面积最大的沙漠，它是？',o:['腾格里沙漠','毛乌素沙漠','塔克拉玛干沙漠','库布齐沙漠'],a:2,e:'塔克拉玛干沙漠位于塔里木盆地腹地，是我国面积最大的沙漠，也是世界第二大流动沙漠，被称为“死亡之海”，是全球气候最干旱的区域之一。'},
{c:'塔里木盆地',q:'塔里木盆地的城镇、人口和交通线，最集中的分布区域是？',o:['盆地边缘的山麓地带和河流沿岸的绿洲','盆地内部的沙漠腹地','盆地周边的高海拔山地','远离水源的戈壁滩'],a:0,e:'塔里木盆地气候极端干旱，水源是人口与城镇分布的决定性因素；盆地边缘的山麓地带和河流沿岸，有高山冰雪融水补给，形成了连片绿洲，是城镇、人口和交通线的核心分布区。'},
{c:'塔里木盆地',q:'塔里木盆地绿洲农业的核心灌溉水源来自？',o:['大气降水','河流水','高山冰雪融水和山地降水','深层地下水'],a:2,e:'塔里木盆地内部年降水量普遍不足50毫米，大气降水无法满足农业需求；绿洲农业的核心水源来自周边天山、昆仑山的高山冰雪融水，以及少量山地降水，水源直接决定了绿洲的规模与分布。'},
{c:'塔里木盆地',q:'塔里木盆地被称为“干旱的宝地”，这里的“宝地”核心是指盆地内储量极其丰富的？',o:['水资源','森林资源','油气资源','耕地资源'],a:2,e:'塔里木盆地气候干旱、水土资源匮乏，但盆地内蕴藏着极为丰富的石油和天然气资源，油气储量约占全国陆上总储量的1/4，是我国重要的能源战略基地，因此被称为“干旱的宝地”。'},
{c:'塔里木盆地',q:'我国西部大开发标志性工程中，将塔里木盆地的天然气输送到东部地区的是？',o:['南水北调','西电东送','西气东输','北煤南运'],a:2,e:'西气东输工程是我国跨区域资源调配的核心工程，一线工程西起塔里木盆地的轮南油气田，东至上海，将盆地内丰富的天然气输送到能源短缺的东部地区，实现了东西部优势互补。'},
{c:'塔里木盆地',q:'西气东输一线工程的起点，位于塔里木盆地的？',o:['轮南油气田','克拉玛依油田','大庆油田','胜利油田'],a:0,e:'西气东输一线工程是我国距离最长、口径最大的输气管道，起点位于塔里木盆地的轮南油气田，终点为上海市，线路全长超4200千米，途经9个省级行政区。'},
{c:'塔里木盆地',q:'我国最大的内流河，流经塔里木盆地北部，被称为新疆“母亲河”的是？',o:['长江','黄河','塔里木河','额尔齐斯河'],a:2,e:'塔里木河是我国最大的内流河，流经塔里木盆地北部，水源主要来自天山、昆仑山的高山冰雪融水，是盆地内绿洲农业、生态环境和居民生产生活的核心水源，被誉为新疆的“母亲河”。'},
{c:'塔里木盆地',q:'塔里木盆地发展农业生产最突出的优势气候条件是？',o:['降水丰富，水源充足','全年温和湿润，无霜期长','夏季高温，光照充足，昼夜温差大','冬季寒冷，降雪量大'],a:2,e:'塔里木盆地属于温带大陆性气候，夏季气温高、晴天多，光照充足，作物光合作用效率高；昼夜温差极大，夜晚作物呼吸作用弱，养分消耗少、积累多，是瓜果、棉花等作物优质高产的核心优势。'},
{c:'塔里木盆地',q:'塔里木盆地是我国规模最大、品质最优的哪种经济作物生产基地？',o:['水稻','甘蔗','长绒棉','油菜'],a:2,e:'塔里木盆地夏季光热充足、昼夜温差大，配合稳定的灌溉水源，具备长绒棉生长的绝佳条件，是我国最大的长绒棉生产基地，棉花纤维长、品质优，产量常年位居全国首位。'},
{c:'塔里木盆地',q:'塔里木盆地的公路、铁路大多沿盆地边缘呈环状分布，核心影响因素是？',o:['水源和城镇分布','盆地内部的沙漠地形','高海拔的山地环境','矿产资源分布'],a:0,e:'塔里木盆地的交通线呈环状分布的核心原因是：盆地边缘的绿洲是水源、人口和城镇的集中分布区，交通线沿绿洲修建，能够串联沿线城镇，服务居民生产生活，带动区域经济发展。'},
{c:'塔里木盆地',q:'塔里木盆地最突出、最严峻的生态环境问题是？',o:['土地荒漠化','水体富营养化','酸雨污染','森林锐减'],a:0,e:'塔里木盆地气候干旱、植被稀少，生态环境极其脆弱；加上过度开垦、过度放牧、不合理用水等人类活动，土地荒漠化问题尤为突出，绿洲边缘的荒漠化扩张是当地生态保护的核心难题。'},
{c:'塔里木盆地',q:'西气东输工程对塔里木盆地所在西部地区的意义，不包括下列哪一项？',o:['将资源优势转化为经济优势','带动相关产业发展，增加就业机会','缓解东部地区的能源短缺问题','完善当地基础设施建设'],a:2,e:'西气东输对西部地区的核心意义包括：将油气资源优势转化为经济优势，带动油气、基建等相关产业发展，增加就业岗位，完善当地基础设施；而缓解东部地区能源短缺，是该工程对东部地区的意义，并非对西部地区的意义。'},
{c:'塔里木盆地',q:'塔里木盆地的油气资源，主要通过哪种运输方式输送到我国东部地区？',o:['公路运输','铁路运输','水路运输','管道运输'],a:3,e:'管道运输具有运输量大、连续性强、损耗小、安全稳定、运营成本低的特点，是石油、天然气等流体物资的最优运输方式，因此塔里木盆地的油气资源主要通过管道运输，经西气东输工程输送至东部地区。'},
{c:'塔里木盆地',q:'下列措施中，不利于塔里木盆地绿洲生态环境保护的是？',o:['合理分配河流上中下游水资源','退耕还林还草，恢复天然植被','推广滴灌、喷灌等节水农业技术','大规模开垦荒地，扩大耕地面积'],a:3,e:'塔里木盆地水资源极度匮乏，大规模开垦荒地会加剧水资源消耗，破坏地表原生植被，加速土地荒漠化进程，直接威胁绿洲的生态安全；其余三项均是保护绿洲生态环境的科学合理措施。'},
{c:'塔里木盆地',q:'西气东输工程对我国东部地区的核心积极影响是？',o:['加剧东部地区的大气污染','增加东部地区的能源供应压力','阻碍东部地区的经济发展','优化能源结构，改善大气环境质量'],a:3,e:'西气东输为东部地区输送了清洁高效的天然气，能够优化东部地区以煤炭为主的能源结构，大幅减少煤炭燃烧产生的污染物排放，改善大气环境质量，同时缓解东部地区能源短缺问题，助力经济高质量发展。'},
{c:'塔里木盆地',q:'下列关于塔里木盆地的描述，正确的是？',o:['位于新疆北部，阿尔泰山与天山之间','是我国面积最小的内陆盆地','气候极端干旱，是我国降水最少的极端干旱区','降水充沛，河网密布，水资源丰富'],a:2,e:'塔里木盆地位于新疆南部，是我国面积最大的内陆盆地；深居内陆、山脉阻隔，海洋水汽难以到达，年降水量普遍不足50毫米，气候极端干旱，是我国降水最少、最干旱的区域，内部沙漠广布，河流稀少。'},
{c:'塔里木盆地',q:'下列关于塔里木盆地的说法，错误的是？',o:['是我国油气资源最丰富的盆地之一','内部的塔克拉玛干沙漠是我国最大的沙漠','城镇和交通线多沿盆地边缘呈环状分布','是我国重要的水稻种植主产区'],a:3,e:'塔里木盆地气候极端干旱，水资源极度匮乏，不适宜种植高耗水的水稻，当地主要种植小麦、玉米等旱作粮食作物，以及长绒棉、瓜果等特色经济作物；其余三项均为关于塔里木盆地的正确表述。'}
);

// ─────────────────────────────────────────────
// 八下·第十章 青藏地区
// ─────────────────────────────────────────────

// C10_S1 青藏地区概况（原4题，追加10题）
window.QB_G8_C10_S1.push(
  {c:'青藏地区',q:'青藏高原为什么被称为"世界屋脊"？',o:['因为它是世界上最大的高原','因为平均海拔超过4000m，是世界上海拔最高的高原，站在青藏高原极目远眺，感觉站在世界之巅','因为它最古老','因为它最宽广'],a:1,e:'青藏高原：面积约250万km²，平均海拔4000-5000m，是世界上面积最大、海拔最高的高原。主体在西藏和青海，由欧亚板块与印度洋板块碰撞抬升而成，形成时间约5000万年前开始。'},
  {c:'青藏',q:'青藏高原高寒气候的主要特点有哪些？',o:['全年高温，无寒冷','气温低（年均<0℃或略高）、昼夜温差极大（>20℃）、太阳辐射强（紫外线强）、降水少（内陆高原）、风力大','全年多雨','无明显季节变化'],a:1,e:'青藏高寒气候：①年均气温低（拉萨约7℃，但多晴天，日最高可达20℃+）②昼夜温差大（因稀薄大气保温差）③太阳辐射强（海拔高，大气薄，直射强）④内部降水少④大风天数多。'},
  {c:'青藏',q:'青藏高原上的居民日常生活有哪些独特之处？（与高寒环境相关）',o:['和平原地区无任何差别','身着厚实藏袍（昼夜温差大，袍可宽可窄），饮酥油茶（高热量，防寒），吃糌粑（青稞面，耐储耐饿），骑牦牛（高原适应），信仰藏传佛教','以水稻为主食','全年穿夏装'],a:1,e:'藏族高寒生活适应：①藏袍（一袍两用，白天腰间系绳，夜晚可披为被）②酥油茶（牦牛黄油+砖茶+盐，热量高御寒）③糌粑（炒青稞面，可干吃，适合游牧携带）④牦牛（毛厚耐寒，提供奶肉皮）。'},
  {c:'青藏',q:'青藏高原的农业生产分布在哪里？为什么？',o:['在高原腹地的大面积种植','主要集中在海拔较低的河谷（雅鲁藏布江谷地、湟水谷地），因为河谷海拔低（2000-3000m），气温相对较高（热量较充足），有灌溉水源','在高原顶部（5000m以上）','只靠温室大棚'],a:1,e:'河谷农业：青藏高原上可种植地基本在河谷：①雅鲁藏布江谷地（西藏南部，日喀则等，种青稞、冬小麦）②湟水谷地（青海，西宁附近，种冬小麦、油菜）③大通河谷等。原因：河谷海拔低，气温高2-4℃，是高寒高原的"温暖宝地"。'},
  {c:'青藏',q:'拉萨被称为"日光城"，原因是什么？',o:['拉萨全年高温','拉萨海拔约3650m，大气稀薄，云层少，年日照时数达3000小时以上（全国最高之一），阳光充足灿烂','拉萨有太阳能发电站很多','拉萨纬度低日出最早'],a:1,e:'"日光城"拉萨：海拔约3650m，纬度29°N（并不算最低），但大气薄（水汽少，云层少），天空晴朗透明，年日照约3000小时（中国最多地区之一），紫外线极强。布达拉宫的阳光极为灿烂，因此得名。'},
  {c:'青藏',q:'布达拉宫在历史上有什么重要地位？现在的保护状态如何？',o:['是现代建筑，建于20世纪','是西藏政教合一统治的中心（历代达赖喇嘛居所兼行政中心），建于7世纪（松赞干布时期），现为世界文化遗产，是西藏历史文化的最重要象征','是一般的寺庙','是中国最新的宫殿'],a:1,e:'布达拉宫（Potala Palace）：7世纪松赞干布为迎娶文成公主修建（今存建筑主要为17世纪重建），位于拉萨红山（海拔3700m），高达13层（约117m），共999间殿堂，是藏传佛教圣地和西藏古代行政中枢，1994年列入UNESCO世界文化遗产。'},
  {c:'青藏',q:'三江源（青海）是哪三条江的发源地？其生态意义是什么？',o:['长江、黄河、珠江','长江（通天河段）、黄河、澜沧江（→湄公河）；是"中华水塔"，每年向下游输水约600亿立方米','黄河、淮河、海河','长江、黄河、黑龙江'],a:1,e:'三江源（青海南部）：长江（通天河）、黄河、澜沧江的发源地，有"中华水塔"之称，是全国水量最大的高原湿地。保护三江源生态（2005年建国家级自然保护区）是保障中下游数亿人口水资源的战略行动。'},
  {c:'青藏',q:'青藏铁路（格尔木-拉萨段）修建的工程意义是什么？',o:['意义不大，西藏有公路就够了','结束了西藏没有铁路的历史，大幅降低进藏物流成本，促进西藏经济发展，是世界上最高和最长的高原铁路，展示了中国的工程技术实力','只对旅游有意义','是世界上最容易修建的铁路'],a:1,e:'青藏铁路（2006年7月1日通车）：格尔木-拉萨1142km，最高点唐古拉山垭口（5072m，世界铁路最高点）。工程挑战：多年冻土（占全程550km）、高寒缺氧（为工人供氧）、生态保护（设野生动物通道）。通车后进藏货运成本下降约75%。'},
  {c:'青藏',q:'青藏高原对全球气候有什么影响？',o:['对全球气候无影响','青藏高原（"第三极"）：①影响东亚和南亚季风环流（高原热力作用）②是亚洲众多大河的发源地（水塔）③高原冰川是气候变化的敏感指示器（冰川融化加速）④隔绝南北气流，影响中国气候格局','只影响西藏本地气候','使全球变暖'],a:1,e:'青藏高原气候影响：①热力作用：夏季是热源，冬季是冷源，影响东亚季风形成和强弱②动力作用：阻挡冬季风南下，使南亚气候不同于同纬度其他地区③水源：亚洲10多条大河发源于此④冰川：储存全球约1/7的淡水，被称为"第三极"。'},
  {c:'青藏',q:'青藏地区的矿产资源有哪些优势？',o:['矿产极度贫乏','有色金属（铜、铅锌）、锂（盐湖，全球最大锂资源区之一）、钾盐（柴达木盆地察尔汗盐湖，全国最大钾肥基地）、石油（塔里木、柴达木）','只有盐','只有铁矿'],a:1,e:'青藏矿产：①柴达木盆地（青海）：被称为"聚宝盆"，有钾盐（察尔汗盐湖，中国最大钾肥基地）、石油（冷湖油田）、铅锌、煤等②西藏：铜矿（驱龙，世界级大型铜矿）③盐湖锂资源（供电动汽车电池）是战略性资源。'}
);

// C10_S2 青藏高原的发展（原2题，追加10题）
window.QB_G8_C10_S2.push(
  {c:'青藏',q:'青藏高原发展旅游业有哪些优势和限制因素？',o:['只有优势，没有任何限制','优势：独特自然景观（雪山、草甸、湖泊）+藏传佛教文化+稀有动植物；限制：高原反应（低氧）、交通不便、生态脆弱、基础设施薄弱','只有限制因素','发展旅游对生态无任何影响'],a:1,e:'青藏旅游：优势：①珠峰（攀登圣地）②纳木错（世界最高大湖）③雅鲁藏布大峡谷③林芝桃花④布达拉宫。限制：①高原反应（游客需适应期）②旅游基础设施不足③生态极脆弱（游客过多→垃圾环境问题）。'},
  {c:'青藏',q:'藏羚羊（藏语"Chiru"）保护的现状和措施是什么？',o:['藏羚羊已经灭绝','20世纪90年代因猎取羊绒（沙图什制品）大规模盗猎，种群数量骤降到约6-8万只；通过禁止捕猎、建立可可西里保护区、打击盗猎，目前恢复到约30万只','藏羚羊不是濒危动物','藏羚羊数量一直很多，无需保护'],a:1,e:'藏羚羊保护：1990年代盗猎猖獗（羊绒=沙图什，价格极高），索南达杰等保护人员以生命守护；1997年可可西里建立国家级自然保护区，2019年列为国家公园。目前种群约30万只，从濒危降为近危。中国反盗猎最著名案例。'},
  {c:'青藏',q:'西藏和青海的经济发展方向是什么？',o:['大规模重化工业发展','以生态保护为前提：绿色农牧业（有机牦牛产品）、生态旅游（高质量小规模）、清洁能源（太阳能、水电）、特色文化产业（藏药、藏医、藏族艺术）','大量采矿出口原矿','完全依靠中央财政转移'],a:1,e:'青藏绿色发展：①有机农牧业（高原牦牛、藏系羊，绿色无污染）②生态旅游（限流精品旅游）③清洁能源（太阳能装机量大，雅江水电）④藏药（止血草、红景天等高原药材）⑤生态补偿（保护三江源获得国家补偿）。'},
  {c:'青藏',q:'青藏高原冰川融化加速对下游地区有何影响？',o:['对下游无任何影响','短期：冰川融水增加，下游洪水风险增加；长期：冰川持续减少，下游水源减少（中长期水危机），影响亿万人的饮水和灌溉','使下游干旱立即消失','只影响高原本地'],a:1,e:'青藏冰川（储存全球约1/7淡水）融化影响：①近期：融水增多，下游河流夏季洪水增加②长期（50-100年）：冰川大量消融后，夏季融水减少（冰川"过了顶点"），亚洲众多依赖高山融雪的大河（黄河、长江、恒河等）流量减少。'},
  {c:'青藏',q:'青藏高原的牦牛对高原生活的适应性表现在哪些方面？',o:['牦牛不适合高原生活','体型大毛发厚实（防寒）、红细胞多（耐低氧）、蹄子宽大（适合高原地形）、耐寒耐粗饲料；为藏民提供奶、肉、皮毛、运输等全方位资源，是"高原之舟"','牦牛只产肉','牦牛不是藏族重要动物'],a:1,e:'牦牛高原适应：①血红蛋白含量是普通牛的3倍（携氧能力强）②厚密毛发（可御-30℃严寒）③蹄宽广（防滑，适合山地碎石）④耐粗饲（吃高原稀疏草）。藏民利用：奶（酥油）、肉、皮（制革）、毛（制袍）、粪（燃料），是高原游牧经济的支柱。'},
  {c:'青藏',q:'青藏高原的太阳能资源为什么特别丰富？',o:['因为纬度最低','海拔高（大气稀薄）、晴天多（少云雾）、大气对太阳辐射削弱少，年太阳辐射量居全国第一；拉萨、昌都等地年均日照超3000小时，是发展光伏的绝佳地区','因为气温最高','因为离太阳最近'],a:1,e:'青藏高原太阳能极丰富原因：①海拔高（大气层薄），大气对太阳辐射吸收散射少②云层少（内陆高原，水汽少）③高原面年日照3000-3500小时（全国最多）。中国大型光伏（太阳能电站）大量建设在青海（格尔木）和西藏（拉萨附近）。'},
  {c:'青藏',q:'雅鲁藏布江的水能资源有多丰富？已有哪些开发计划？',o:['水能不丰富，不值得开发','雅鲁藏布江大峡谷段（全球最大峡谷）落差达2000多米，水能储量约7000万千瓦，超过三峡；已规划和部分建设多个大型梯级水电站','只有少量水能','已全部开发完毕'],a:1,e:'雅鲁藏布江水能：大峡谷段（直径县至墨脱）落差超2000m，全球最密集水能区。"藏东南水电构想"总装机可达约1亿千瓦（相当于5个三峡），是中国未来最重要的水电开发区。藏木水电站（2014年）已建成，多个梯级站在规划中。'},
  {c:'青藏',q:'"高原反应"（高山病）是什么？如何预防？',o:['是一种传染病','因大气含氧量随海拔升高而降低（海拔4000m含氧量约为海平面60%），造成头痛、心跳加速、恶心、气短等症状；预防：初到高原要休息适应，不剧烈运动，必要时吸氧','是由于气温太低导致','是藏族特有的疾病'],a:1,e:'高原反应预防：①初到高原（2500m以上）头2-3天减少活动，充分休息②不饮酒（加重缺氧）③多喝水（预防脱水）④必要时服用高原安等药物⑤严重时吸氧或下撤⑥心肺疾病患者禁止进入高海拔地区。'},
  {c:'青藏',q:'为什么说保护青藏高原生态是全国性的大事？',o:['只是地区性问题','青藏高原是亚洲大江大河（长江黄河澜沧江雅鲁藏布江）的发源地（"中华水塔"），保护其植被和冻土可维持水源稳定；高原生态破坏影响下游数亿人口的水资源安全','和内地无关','只影响藏族同胞'],a:1,e:'青藏生态意义：①长江黄河等源区，维护植被=维护水量稳定②高原冻土融化释放CO₂和甲烷（温室气体，加速全球变暖）③高原湿地（三江源）是全球最重要碳汇之一④高原生态崩溃→下游水旱灾害加剧。习近平提出"保护好雪域高原的生灵草木、万水千山"。'},
  {c:'青藏',q:'青藏地区的公路建设面临哪些挑战？代表性公路有哪些？',o:['地形平坦，建设容易','多年冻土（路基沉陷）、高寒（施工窗口期短）、高海拔缺氧（施工人员健康）、地质灾害（泥石流、雪崩）；代表：川藏公路（318国道）、青藏公路','只有高原反应一个问题','公路建设已全部完成，无难题'],a:1,e:'青藏公路挑战：①多年冻土（夏季融化路面凹陷，热棒技术处理）②年冻融交替导致路面破损③施工人员高原反应④泥石流/崩塌频发。典型：川藏公路（2000km，最险）；青藏公路（格尔木-拉萨，海拔最高）；新川藏铁路（在建，预计2030年前后建成）。'}
);

