// 八下·第十一章 奋进中的中国
// ─────────────────────────────────────────────

// C11（原4题，追加10题）
window.QB_G8_C11.push(
  {c:'中国',q:'中国提出"共同富裕"的目标，主要解决什么问题？',o:['提高全国平均GDP','解决区域发展不均衡（东富西穷）和居民收入差距扩大的问题，实现全体人民共同享有发展成果','只是政治口号','只针对农村地区'],a:1,e:'"共同富裕"（习近平提出，强调）：缩小城乡差距、区域差距、收入差距。措施：①精准扶贫（2020年全面脱贫）②西部大开发③东西部对口支援④农村振兴战略⑤缩小基本公共服务差距（教育医疗均等化）。'},
  {c:'中国',q:'"乡村振兴战略"的主要目标是什么？',o:['让所有农民进城','产业兴旺、生态宜居、乡风文明、治理有效、生活富裕；建设美丽乡村，解决三农（农业农村农民）问题','只发展农业一项','取消农村建设城市'],a:1,e:'乡村振兴：①产业：发展现代农业、农村电商（带货助农）②生态：农村人居环境整治（垃圾污水处理）③文化：弘扬优秀乡土文化④治理：加强农村基层党组织⑤生活：提高农民收入（脱贫攻坚成果巩固）。'},
  {c:'中国',q:'中国"脱贫攻坚"战略取得了什么历史成就？',o:['尚未实现任何脱贫','2021年底全面建成小康社会，完成消除农村绝对贫困，约9899万贫困人口全部脱贫，是人类历史上规模最大的减贫成就','脱贫率只有50%','脱贫工作尚在进行中'],a:1,e:'2020年底脱贫攻坚战全面胜利：832个贫困县全部摘帽，9899万农村贫困人口全部脱贫，创造了人类减贫史上的奇迹。被联合国等国际组织高度肯定，为全球减贫做出了卓越贡献。'},
  {c:'中国',q:'中国区域协调发展战略包括哪些重要内容？',o:['只有西部大开发','西部大开发（西部）、中部崛起（中部）、振兴东北（东北）、东部率先发展，以及京津冀协同发展、长三角一体化、粤港澳大湾区等重大战略','只有东部发展','只有中部崛起'],a:1,e:'区域协调：①西部大开发（2000~）②中部崛起（2006~）③振兴东北（2003~）④东部率先。城市群战略：⑤京津冀协同⑥长三角一体化⑦粤港澳大湾区⑧成渝双城经济圈。目标：各地区各展所长，协调联动。'},
  {c:'中国',q:'中国的科技创新发展取得了哪些重要成就？',o:['中国科技完全依赖进口','航天（空间站、嫦娥探月、天问探火）、高铁（世界最长高铁网）、超级计算机（曾多次排名第一）、5G（全球最大规模5G网络）、量子通信等多领域领先全球','科技水平不高','只在制造业有优势'],a:1,e:'中国科技成就：①航天：神舟系列、天宫空间站（2022年建成）、嫦娥五号（月球采样）、天问一号（火星探测）②高铁：运营里程全球第一③5G：基站数量全球第一④量子通信（墨子号卫星）⑤超算（神威太湖之光等）。'},
  {c:'中国',q:'中国推进"一带一路"建设的意义是什么？',o:['只是外交活动','推动基础设施互联互通，扩大与沿线国家的贸易投资合作，共享中国发展红利，推进"人类命运共同体"构建，已有140多个国家参与','只对中国有利','只建设交通设施'],a:1,e:'"一带一路"（BRI，2013年提出）：140+国家参与，投资建设港口、铁路、电站等基础设施，推进贸易投资便利化。中巴经济走廊、匈塞铁路、比雷埃夫斯港是典型项目。也面临债务问题和地缘政治争议。'},
  {c:'中国',q:'中国建设"生态文明"的主要行动有哪些？',o:['只是政策宣传，无实际行动','划定生态红线、国家公园体系、碳交易市场、清洁能源替代、河长制湖长制（流域管理）、大规模植树造林（三北防护林、国家储备林）等','完全没有行动','只靠自然恢复'],a:1,e:'生态文明实践：①生态红线（禁止开发）②国家公园（三江源、大熊猫、东北虎豹等5个先期建立）③全国碳交易市场（2021年启动）④"双碳"目标⑤退耕还林（25年造林约7000万公顷，全球最多）⑥河长制（各级官员负责辖区水域治理）。'},
  {c:'中国',q:'"粮食安全"为什么对中国如此重要？',o:['中国粮食完全自给自足，无需担心','中国14亿人口，粮食需求量大；历史上多次发生饥荒，教训深刻；受耕地减少、气候变化、国际贸易等威胁，确保粮食供给安全事关国家稳定和百姓生活','中国可以完全依赖进口','粮食不重要，科技食品可以替代'],a:1,e:'粮食安全：中国人均耕地少（不足世界平均40%），粮食需求总量极大（约7亿吨/年）。习近平指示："中国人的饭碗任何时候都要牢牢端在自己手中，我们的饭碗应该主要装中国粮"。确保口粮（水稻小麦）绝对自给率>95%是底线。'},
  {c:'中国',q:'中国人口城镇化的发展对地理格局有哪些影响？',o:['使农村人口增多','大量人口向城市集中（城镇化率从1978年约18%升至2022年约65%），形成城市群格局，农村出现留守老人儿童问题，但促进了经济发展和现代化','农村人口不减少','东部城市人口减少'],a:1,e:'城镇化影响：①城市群（长三角、珠三角、京津冀、成渝）快速崛起②农村土地流转（农业规模化）③"农民工"群体（约3亿）流动就业④城市基础设施需大量投资⑤农村空心化（留守问题）⑥城市"大城市病"⑦农业劳动力减少推动机械化。'},
  {c:'中国',q:'中国"新基建"（新型基础设施建设）包括哪些领域？',o:['只包括铁路公路','5G网络、数据中心、人工智能（AI）、工业互联网、特高压输电、城际高铁（轨道交通）、新能源充电桩（电动汽车）等七大领域','只包括房地产建设','只包括工厂建设'],a:1,e:'"新基建"（2020年后国家重点投资）：①信息基础设施：5G、大数据中心、AI、工业互联网②融合基础设施：智能交通（自动驾驶）、智能电网③创新基础设施：科研院所、国家实验室。是推动数字经济和制造业升级的核心。'}
);

